36	const PROCESSING_FEE = 5;
37	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
38	
39	const BASE_PREMIUM: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	};
46	
47	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
48	const BLOCK_BASE = 60;
49	
50	const baseForGroup = (type: string, count: number): number => {
51	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
52	  return count * (BASE_PREMIUM[type] ?? 0);
53	};
54	
55	const quotePremium = (step: QuoteStep): StepResult => {
56	  const counts = new Map<string, number>();
57	  for (const item of step.items) {
58	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
59	  }
60	  let baseTotal = 0;
61	  for (const [type, count] of counts) {
62	    baseTotal += baseForGroup(type, count);
63	  }
64	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
65	  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
66	};
67	
68	const processStep = (step: Step): StepResult => {
69	  if (step.op === "quote") return quotePremium(step);
70	  return { payout: 0, remainingCap: 0 };
71	};
72	
73	export const runScenario = (scenario: Scenario): ScenarioResult => ({
74	  results: scenario.steps.map(processStep),
